import Navbar from "@/app/components/Navbar";
import Footer from "@/app/components/Footer";
import JobsPageClient from "./JobsPageClient";
import { getJobs, getJobFilters } from "@/app/actions/jobs";

export default async function JobsPage({
    searchParams,
}: {
    searchParams: Promise<{ q?: string; loc?: string; type?: string; industry?: string; salary?: string }>;
}) {
    const params = await searchParams;

    const filters = await getJobFilters();

    let industryId = undefined;
    if (params.industry) {
        const industry = filters.industries.find(i => i.slug === params.industry);
        if (industry) {
            industryId = industry.id;
        }
    }

    const jobs = await getJobs({
        q: params.q,
        loc: params.loc,
        type: params.type,
        industryId: industryId,
        salary: params.salary,
        status: "ACTIVE"
    }).catch(() => []);

    return (
        <JobsPageClient
            jobs={jobs}
            filters={filters}
            searchParams={params}
        />
    );
}
